function candidate(input) {
  if (!input || typeof input.token !== "string" || !/^[!#$%&'*+.^_`|~0-9A-Za-z-]+(?:\/[!#$%&'*+.^_`|~0-9A-Za-z-]+)?$/.test(input.token)) {
    throw new TypeError("invalid token");
  }

  var output = input.token.toLowerCase();
  var extras = input.attributes;

  if (extras && typeof extras === "object" && !Array.isArray(extras)) {
    Object.keys(extras).sort().forEach(function (key) {
      var value = String(extras[key]);
      if (key.charAt(key.length - 1) === "*") {
        output += "; " + key + "=" + value;
      } else {
        output += "; " + key + "=\"" + value.replace(/[\\"]/g, "\\$&") + "\"";
      }
    });
  }

  return output;
}
